import axios from 'axios';

// Base URL for backend API
const API_BASE_URL = 'http://localhost:5000/api';

// Create axios instance
const api = axios.create({
  baseURL: API_BASE_URL,
});

// Interceptor to add JWT token from localStorage to every request
api.interceptors.request.use((config) => {
  const token = localStorage.getItem('token'); // get real JWT token
  if (token) {
    config.headers.Authorization = `Bearer ${token}`;
  }
  return config;
});

// Authentication API functions
export const authAPI = {
  login: async (email, password) => {
    const response = await api.post('/auth/login', { email, password }); // backend route must match
    return response.data; // { token, user }
  },
  register: async (userData) => {
    const response = await api.post('/auth/signup', userData); // signup route
    return response.data;
  },
  verifyToken: async () => {
    const response = await api.get('/auth/verify-token'); // optional route if implemented
    return response.data;
  },
};

// Expenses API functions
export const expenseAPI = {
  getAll: async () => {
    const response = await api.get('/expenses');
    return response.data;
  },
  getRecentExpenses: async () => {
    const response = await api.get('/expenses/recent');
    return response.data;
  },
  create: async (expenseData) => {
    const response = await api.post('/expenses', expenseData);
    return response.data;
  },
  update: async (id, expenseData) => {
    const response = await api.put(`/expenses/${id}`, expenseData);
    return response.data;
  },
  delete: async (id) => {
    const response = await api.delete(`/expenses/${id}`);
    return response.data;
  },
  getDashboardStats: async () => {
    const response = await api.get('/expenses/dashboard');
    return response.data;
  },
  getAnalytics: async (timeRange = '6months') => {
    const response = await api.get(`/expenses/analytics?timeRange=${timeRange}`);
    return response.data;
  },
  getSpendingByCategory: async () => {
    const response = await api.get('/expenses/spending');
    return response.data;
  },
};

export const incomeAPI = {
  getAll: async () => {
    const response = await api.get('/income');
    return response.data;
  },
  create: async (incomeData) => {
    const response = await api.post('/income', incomeData);
    return response.data;
  },
  update: async (id, incomeData) => {
    const response = await api.put(`/income/${id}`, incomeData);
    return response.data;
  },
  delete: async (id) => {
    const response = await api.delete(`/income/${id}`);
    return response.data;
  },
  getTotal: async () => {
    const response = await api.get('/income/total');
    return response.data;
  },
};

export const budgetAPI = {
  getBudgets: async () => {
    const response = await api.get('/budgets');
    return response.data;
  },
  setBudget: async (budgetData) => {
    const response = await api.post('/budgets', budgetData);
    return response.data;
  },
};

// Default export
export default api;
